        $merged = Merge-TestResults -Results @($r1, $r2)
        $flakyNames = $merged.FlakyTests | Select-Object -ExpandProperty Name
        $flakyNames | Should -Contain "Test2"
        $flakyNames | Should -Contain "Test3"
        $flakyNames | Should -Contain "Test4"
